import React, { useState, useEffect } from 'react'
import Counter from './Counter'

function App() {
  // State 선언 : const isCounter = false
  const [isCounter, setIsCounter] = useState(false)

  const onClick = () => {
    // State 변경 : isCounter = true
    setIsCounter(true)
  }

  return (
    <>
      <button onClick={onClick}>On</button>
      { isCounter && <Counter /> }
    </>
  )
}

export default App
